# Verify replica set status
kubectl exec -n mongodb mongodb-replica-1 -- mongosh \
  -u admin-user -p admin123password --authenticationDatabase admin \
  --eval '
var status = rs.status();
print("RS name:", status.set);
status.members.forEach(m => print("  Member:", m.name, "state:", m.stateStr));
' --quiet 2>&1

# Write and read data as app-user
kubectl exec -n mongodb mongodb-replica-1 -- mongosh \
  -u app-user -p app123password --authenticationDatabase appdb \
  --eval '
var db = db.getSiblingDB("appdb");
db.testcol.insertOne({ msg: "hello from karma", ts: new Date() });
var doc = db.testcol.findOne({ msg: "hello from karma" });
print("Read back:", JSON.stringify(doc.msg));
print("Write/read OK");
' --quiet 2>&1

# Increase memory limit to avoid OOM kills during concurrent mongosh
kubectl patch statefulset mongodb-replica -n mongodb --type=json -p='[
  {"op": "replace", "path": "/spec/template/spec/containers/0/resources/limits/memory", "value": "1Gi"},
  {"op": "replace", "path": "/spec/template/spec/containers/0/resources/requests/memory", "value": "512Mi"}
]'

# Full verification: RS status + data write/read
kubectl exec -n mongodb mongodb-replica-1 -- mongosh \
  -u admin-user -p admin123password --authenticationDatabase admin \
  --eval '
// RS health check
var status = rs.status();
print("=== Replica Set Status ===");
print("Name:", status.set);
status.members.forEach(function(m) {
  print("  ", m.name, "->", m.stateStr);
});

// Verify both members: 1 PRIMARY + 2 SECONDARY
var primary = status.members.filter(function(m){ return m.stateStr === "PRIMARY" });
var secondary = status.members.filter(function(m){ return m.stateStr === "SECONDARY" });
print("PRIMARY count:", primary.length);
print("SECONDARY count:", secondary.length);
' --quiet 2>&1

# Write and read data as app-user
kubectl exec -n mongodb mongodb-replica-1 -- mongosh \
  -u app-user -p app123password --authenticationDatabase appdb \
  --eval '
var appdb = db.getSiblingDB("appdb");
appdb.testcol.insertOne({ msg: "hello-karma", ts: "2026-07-04" });
var doc = appdb.testcol.findOne({ msg: "hello-karma" });
print("Read:", doc.msg, "- Write/read OK");
' --quiet 2>&1
